package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  void testGenerateNonExecutableJson_setsFlagAndReturnsThis() throws Exception {
    // Initially, the generateNonExecutableJson field should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("generateNonExecutableJson");
    field.setAccessible(true);
    boolean initialValue = (boolean) field.get(gsonBuilder);
    assertFalse(initialValue, "Initial generateNonExecutableJson should be false");

    // Call the focal method
    GsonBuilder returned = gsonBuilder.generateNonExecutableJson();

    // Assert the method returns the same instance (this)
    assertSame(gsonBuilder, returned, "generateNonExecutableJson should return this");

    // Assert the generateNonExecutableJson field is set to true
    boolean updatedValue = (boolean) field.get(gsonBuilder);
    assertTrue(updatedValue, "generateNonExecutableJson should be true after calling method");
  }
}
